protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // HasIndex throws at startup in EF Core 9 Cosmos — manage indexing
    // via the container's indexing policy (Azure Portal / Bicep / Terraform).

    modelBuilder.Entity<Product>(b =>
    {
        b.ToContainer("Products");

        // EF Core 9 renamed the discriminator property from "Discriminator" to "$type".
        // Preserve the old name so existing documents and direct SQL queries
        // (e.g. WHERE c.Discriminator = 'Product') continue to work.
        b.HasDiscriminator<string>("Discriminator");

        // EF Core 9 changed id format from "EntityType|KeyValue" to just "KeyValue".
        // Preserve the old format so existing documents (e.g. "Product|123") remain
        // accessible via FindAsync and point-reads.
        b.HasRootDiscriminatorInJsonId(true);
    });
}

